/*
Remove the inheritance of text transform in    
Edge and Firefox.
*/

button,
select {
  text-transform: none;
}

/*
1. Correct the inability to style clickable    
types in iOS and Safari.
2. Remove default button styles.
*/

button,
input:where([type='button']),
input:where([type='reset']),
input:where([type='submit']) {
  -webkit-appearance: button; /* 1 */
  background-color: transparent; /* 2 */       
  background-image: none; /* 2 */
}

/*
Use the modern Firefox focus style for all     
focusable elements.
*/

:-moz-focusring {
  outline: auto;
}

/*
Remove the additional `:invalid` styles in     
Firefox. (https://github.com/mozilla/gecko-dev 
/blob/2f9eacd9d3d995c937b4251a5557d95d494c9be1 
/layout/style/res/forms.css#L728-L737)
*/

:-moz-ui-invalid {
  box-shadow: none;
}

/*
Add the correct vertical alignment in Chrome   
and Firefox.
*/

progress {
  vertical-align: baseline;
}

/*
Correct the cursor style of increment and      
decrement buttons in Safari.
*/

::-webkit-inner-spin-button,
::-webkit-outer-spin-button {
  height: auto;
}

/*
1. Correct the odd appearance in Chrome and    
Safari.
2. Correct the outline style in Safari.        
*/

[type='search'] {
  -webkit-appearance: textfield; /* 1 */       
  outline-offset: -2px; /* 2 */
}

/*
Remove the inner padding in Chrome and Safari  
on macOS.
*/

::-webkit-search-decoration {
  -webkit-appearance: none;
}

/*
1. Correct the inability to style clickable    
types in iOS and Safari.
2. Change font properties to `inherit` in      
Safari.
*/

::-webkit-file-upload-button {
  -webkit-appearance: button; /* 1 */
  font: inherit; /* 2 */
}

/*
Add the correct display in Chrome and Safari.  
*/

summary {
  display: list-item;
}

/*
Removes the default spacing and border for     
appropriate elements.
*/

blockquote,
dl,
dd,
h1,
h2,
h3,
h4,
h5,
h6,
hr,
