  padding: 0;
}

/*
Reset default styling for dialogs.
*/
dialog {
  padding: 0;
}

/*
Prevent resizing textareas horizontally by     
default.
*/

textarea {
  resize: vertical;
}

/*
1. Reset the default placeholder opacity in    
Firefox. (https://github.com/tailwindlabs/tail 
windcss/issues/3300)
2. Set the default placeholder color to the    
user's configured gray 400 color.
*/

input::-moz-placeholder,
textarea::-moz-placeholder {
  opacity: 1; /* 1 */
  color: #9ca3af; /* 2 */
}

input::placeholder,
textarea::placeholder {
  opacity: 1; /* 1 */
  color: #9ca3af; /* 2 */
}

/*
Set the default cursor for buttons.
*/

button,
[role="button"] {
  cursor: pointer;
}

/*
Make sure disabled buttons don't get the       
pointer cursor.
*/
:disabled {
  cursor: default;
}

/*
1. Make replaced elements `display: block` by  
default. (https://github.com/mozdevs/cssremedy 
/issues/14)
2. Add `vertical-align: middle` to align       
replaced elements more sensibly by default. (h 
ttps://github.com/jensimmons/cssremedy/issues/ 
14#issuecomment-634934210)
   This can trigger a poorly considered lint   
error in some tools but is included by design. 
*/

img,
svg,
video,
canvas,
audio,
iframe,
embed,
object {
  display: block; /* 1 */
  vertical-align: middle; /* 2 */
}

/*
Constrain images and videos to the parent      
width and preserve their intrinsic aspect      
ratio. (https://github.com/mozdevs/cssremedy/i 
ssues/14)
*/

